  1	{
  2	  "$schema": "https://json-schema.org/draft/2020-12/schema",
  3	  "title": "EDEN event envelope",
  4	  "description": "The envelope every event appended to an EDEN event log MUST carry. Registered types have per-type payload shapes enumerated under allOf; types outside the registry pass the envelope only. Full normative registry and semantics are in 05-event-protocol.md.",
  5	  "type": "object",
  6	  "required": ["event_id", "type", "occurred_at", "experiment_id", "data"],
  7	  "properties": {
  8	    "event_id": {
  9	      "type": "string",
 10	      "minLength": 1,
 11	      "description": "Unique identifier for this event within the log."
 12	    },
 13	    "type": {
 14	      "type": "string",
 15	      "pattern": "^[a-z][a-z0-9_]*(\\.[a-z][a-z0-9_]*)+$",
 16	      "description": "Dotted type name, e.g. task.claimed, trial.succeeded."
 17	    },
 18	    "occurred_at": {
 19	      "type": "string",
 20	      "format": "date-time",
 21	      "pattern": "^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}(\\.[0-9]+)?Z$",
 22	      "description": "When the state change happened; UTC (trailing Z) required."
 23	    },
 24	    "experiment_id": {
 25	      "type": "string",
 26	      "minLength": 1
 27	    },
 28	    "data": {
 29	      "type": "object",
 30	      "description": "Type-specific payload; shape fixed by the registry entry for the event's type."
 31	    }
 32	  },
 33	  "$defs": {
 34	    "taskId": {"type": "string", "minLength": 1},
 35	    "proposalId": {"type": "string", "minLength": 1},
 36	    "trialId": {"type": "string", "minLength": 1},
 37	    "workerId": {"type": "string", "minLength": 1},
 38	    "taskKind": {"type": "string", "enum": ["plan", "implement", "evaluate"]},
 39	    "commitSha": {"type": "string", "pattern": "^[0-9a-f]{40}([0-9a-f]{24})?$"},
 40	    "failReason": {"type": "string", "enum": ["worker_error", "validation_error", "policy_limit"]},
 41	    "reclaimCause": {"type": "string", "enum": ["expired", "operator", "health_policy"]}
 42	  },
 43	  "allOf": [
 44	    {
 45	      "if": {"properties": {"type": {"const": "task.created"}}, "required": ["type"]},
 46	      "then": {
 47	        "properties": {
 48	          "data": {
 49	            "type": "object",
 50	            "required": ["task_id", "kind"],
 51	            "properties": {
 52	              "task_id": {"$ref": "#/$defs/taskId"},
 53	              "kind": {"$ref": "#/$defs/taskKind"}
 54	            }
 55	          }
 56	        }
 57	      }
 58	    },
 59	    {
 60	      "if": {"properties": {"type": {"const": "task.claimed"}}, "required": ["type"]},
 61	      "then": {
 62	        "properties": {
 63	          "data": {
 64	            "type": "object",
 65	            "required": ["task_id", "worker_id"],
 66	            "properties": {
 67	              "task_id": {"$ref": "#/$defs/taskId"},
 68	              "worker_id": {"$ref": "#/$defs/workerId"}
 69	            }
 70	          }
 71	        }
 72	      }
 73	    },
 74	    {
 75	      "if": {"properties": {"type": {"const": "task.submitted"}}, "required": ["type"]},
 76	      "then": {
 77	        "properties": {
 78	          "data": {
 79	            "type": "object",
 80	            "required": ["task_id"],
 81	            "properties": {
 82	              "task_id": {"$ref": "#/$defs/taskId"}
 83	            }
 84	          }
 85	        }
 86	      }
 87	    },
 88	    {
 89	      "if": {"properties": {"type": {"const": "task.completed"}}, "required": ["type"]},
 90	      "then": {
 91	        "properties": {
 92	          "data": {
 93	            "type": "object",
 94	            "required": ["task_id"],
 95	            "properties": {
 96	              "task_id": {"$ref": "#/$defs/taskId"}
 97	            }
 98	          }
 99	        }
100	      }
101	    },
102	    {
103	      "if": {"properties": {"type": {"const": "task.failed"}}, "required": ["type"]},
104	      "then": {
105	        "properties": {
106	          "data": {
107	            "type": "object",
108	            "required": ["task_id", "reason"],
109	            "properties": {
110	              "task_id": {"$ref": "#/$defs/taskId"},
111	              "reason": {"$ref": "#/$defs/failReason"}
112	            }
113	          }
114	        }
115	      }
116	    },
117	    {
